function report = runAdaptiveHierarchyControls(options)
%RUNADAPTIVEHIERARCHYCONTROLS Exercise declared C1 expansion failures.
%
% The committed synthetic controls are evaluation fixtures, not tuning data.
% Each adaptive result is compared both with a full common-label fine WTA and
% with independent pinhole truth. No threshold is changed from the solver.
%
% Traceability: algo/main.tex Algorithm 1 and Eqs. (52)--(76), (121)--(125);
% docs/implementation_plan.md C1 milestone 4.

arguments
    options.Scenarios (1, :) string ...
        {mustBeNonempty, mustBeControlScenarios} = ...
        ["clean", "out-of-range", "under-dense", ...
        "low-texture", "facade-occlusion"]
    options.UseParallel (1, 1) logical = true
    options.NumWorkers (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.MaximumPendingTiles (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.RunSgm (1, 1) logical = false
    options.Display (1, 1) logical = false
    options.Verbose (1, 1) logical = true
end

root = fileparts(fileparts(mfilename("fullpath")));
oldPath = path;
addpath(fullfile(root, "src"));
cleanup = onCleanup(@() path(oldPath));
names = options.Scenarios;
rows = cell(numel(names), 44);
details = cell(numel(names), 1);
base = struct;
calibrator = frozenCalibrator(root);
timer = tic;
for k = 1:numel(names)
    name = names(k);
    if ismember(name, ["clean", "out-of-range", "under-dense"])
        if isempty(fieldnames(base))
            base = analyticControl;
        end
        c = base;
    elseif name == "low-texture"
        c = fixtureControl(root, ...
            "label_density_heldout_low_texture_v1.json", calibrator);
    else
        c = fixtureControl(root, ...
            "label_density_heldout_hillside_buildings_v2.json", calibrator);
    end

    enabled = adaptiveTriggerNames;
    if name == "out-of-range"
        h = c.TrueHeightMetres;
        c.Plan.Tiles.MinimumHeightMetres(1) = h - 3;
        c.Plan.Tiles.MaximumHeightMetres(1) = h - 1;
        c.Plan.Tiles.LabelCount(1) = 3;
        c.Plan.Tiles.HeightLabelsMetres{1} = h + [-3, -2, -1];
        enabled = "FineBoundaryWinner";
    elseif name == "under-dense"
        h = c.TrueHeightMetres;
        c.Plan.Tiles.MinimumHeightMetres(2) = h - 10;
        c.Plan.Tiles.MaximumHeightMetres(2) = h + 10;
        c.Plan.Tiles.LabelCount(2) = 3;
        c.Plan.Tiles.HeightLabelsMetres{2} = h + [-10, 0, 10];
        enabled = "UnderDenseLabels";
    end

    fine = c.Solver.runFineAdaptive(c.Plan, ...
        LabelBlockSize=4, EnabledTriggers=enabled, ...
        UseParallel=options.UseParallel, NumWorkers=options.NumWorkers, ...
        MaximumPendingTiles=options.MaximumPendingTiles, ...
        RunSgm=options.RunSgm, ...
        EvaluateFullReference=true, ...
        ReferenceGeometrySampleGrid=[7, 7]);
    rawTruth = truthMetrics(fine.Raw, c.Truth);
    refinedTruth = truthMetrics(fine.Refined, c.Truth);
    fullTruth = truthMetrics( ...
        fine.FullCommonLabelReference, c.Truth);
    if options.RunSgm
        sgmTruth = truthMetrics(fine.Sgm, c.Truth);
        fullSgmTruth = truthMetrics( ...
            fine.FullCommonLabelSgmReference, c.Truth);
        sgmRemaps = fine.Sgm.RemappedTransitionCount;
        sgmFullRmse = ...
            fine.SgmApproximationMetrics.CorrespondenceEpeRmsePixels;
        sgmFullP95 = ...
            fine.SgmApproximationMetrics.CorrespondenceEpeP95Pixels;
        sgmSeconds = fine.Runtime.SgmSeconds;
    else
        sgmTruth = emptyTruthMetrics;
        fullSgmTruth = emptyTruthMetrics;
        sgmRemaps = 0;
        sgmFullRmse = NaN;
        sgmFullP95 = NaN;
        sgmSeconds = 0;
    end
    t = fine.Warnings.TileTriggers;
    fullWork = fine.FullCommonLabelReference.Runtime.PixelLabelCount;
    adaptiveWork = fine.Runtime.EvaluatedPixelLabelCount;
    rows(k, :) = {name, c.Identifier, c.SurfaceType, c.TextureType, ...
        prod(c.ImageSize), height(t), nnz(t.Triggered), ...
        nnz(t.ExpansionApplied), ...
        nnz(t.InheritedRawBoundaryTrigger), ...
        nnz(t.InheritedSgmBoundaryTrigger), ...
        nnz(t.InheritedInvalidOutputTrigger), ...
        nnz(t.InheritedLowConfidenceTrigger), ...
        nnz(t.InheritedConfidenceInvalidTrigger), ...
        nnz(t.HighTrajectoryCurvatureTrigger), ...
        nnz(t.UnderDenseLabelsTrigger), ...
        nnz(t.FineBoundaryTrigger), nnz(t.FineInvalidTrigger), ...
        nnz(t.CoarseFineDisagreementTrigger), ...
        fine.Runtime.FirstPassPixelLabelCount, ...
        fine.Runtime.ExpansionPixelLabelCount, adaptiveWork, fullWork, ...
        adaptiveWork ./ fullWork, ...
        fine.ApproximationMetrics.ValidityAgreementFraction, ...
        fine.ApproximationMetrics.CorrespondenceEpeRmsePixels, ...
        fine.ApproximationMetrics.CorrespondenceEpeP95Pixels, ...
        rawTruth.Coverage, rawTruth.EpeRmsePixels, ...
        rawTruth.EpeP95Pixels, refinedTruth.Coverage, ...
        refinedTruth.EpeRmsePixels, fullTruth.Coverage, ...
        fullTruth.EpeRmsePixels, sgmRemaps, sgmFullRmse, sgmFullP95, ...
        sgmTruth.Coverage, sgmTruth.EpeRmsePixels, ...
        fullSgmTruth.Coverage, fullSgmTruth.EpeRmsePixels, sgmSeconds, ...
        c.Truth.FacadeFraction, ...
        c.Truth.OcclusionFraction, fine.Runtime.TotalSeconds};
    details{k} = struct("Control", c, "Fine", fine, ...
        "RawTruthMetrics", rawTruth, ...
        "RefinedTruthMetrics", refinedTruth, ...
        "FullTruthMetrics", fullTruth);
    details{k}.SgmTruthMetrics = sgmTruth;
    details{k}.FullSgmTruthMetrics = fullSgmTruth;
end

summary = cell2table(rows, VariableNames=["Scenario", "Fixture", ...
    "SurfaceType", "TextureType", "PixelCount", "TileCount", ...
    "TriggeredTileCount", "ExpandedTileCount", ...
    "InheritedRawBoundaryTriggerCount", ...
    "InheritedSgmBoundaryTriggerCount", ...
    "InheritedInvalidOutputTriggerCount", ...
    "InheritedLowConfidenceTriggerCount", ...
    "InheritedConfidenceInvalidTriggerCount", ...
    "HighTrajectoryCurvatureTriggerCount", ...
    "UnderDenseLabelsTriggerCount", "FineBoundaryTriggerCount", ...
    "FineInvalidTriggerCount", ...
    "CoarseFineDisagreementTriggerCount", ...
    "FirstPassPixelLabelCount", "ExpansionPixelLabelCount", ...
    "AdaptivePixelLabelCount", "FullPixelLabelCount", "WorkRatio", ...
    "FullValidityAgreementFraction", "FullComparisonEpeRmsePixels", ...
    "FullComparisonEpeP95Pixels", "RawTruthCoverage", ...
    "RawTruthEpeRmsePixels", "RawTruthEpeP95Pixels", ...
    "RefinedTruthCoverage", "RefinedTruthEpeRmsePixels", ...
    "FullTruthCoverage", "FullTruthEpeRmsePixels", ...
    "SgmRemappedTransitionCount", ...
    "SgmFullComparisonEpeRmsePixels", ...
    "SgmFullComparisonEpeP95Pixels", ...
    "SgmTruthCoverage", "SgmTruthEpeRmsePixels", ...
    "FullSgmTruthCoverage", "FullSgmTruthEpeRmsePixels", ...
    "SgmSeconds", ...
    "FacadeFraction", "OcclusionFraction", "TotalSeconds"]);
figures = struct;
if options.Display
    figures.Summary = displayControls(summary);
end
report = struct( ...
    "Summary", summary, ...
    "Details", {details}, ...
    "Scenarios", names, ...
    "TotalSeconds", toc(timer), ...
    "RunSgm", options.RunSgm, ...
    "Figures", figures, ...
    "Interpretation", ...
    "fixed C1 controls only; no threshold, confidence, cost, or SGM tuning");
if options.Verbose
    fprintf("Adaptive hierarchy controls\n");
    disp(summary(:, ["Scenario", "TriggeredTileCount", ...
        "ExpandedTileCount", "WorkRatio", ...
        "FullComparisonEpeRmsePixels", "RawTruthEpeRmsePixels"]));
end
clear cleanup
end

function c = analyticControl
renderer = SyntheticPinholeRenderer("adaptive-clean", [96, 112], ...
    MeanObliquityDegrees=60, ConvergenceDegrees=2, ...
    TrueHeightMetres=3, TextureSeed=711);
pair = renderer.renderPair;
calibrator = HeightConfidenceCalibrator(0.1, 0.1, 1, [1, 0.2]);
c = prepareControl(renderer, pair, [-30, 30], calibrator, true);
end

function c = fixtureControl(root, file, calibrator)
path = fullfile(root, "config", "synthetic", file);
specification = jsondecode(fileread(path));
renderer = SyntheticPinholeRenderer.fromJson(path);
pair = renderer.renderPair;
r = specification.movingRadiometry;
pair.MovingImage = SyntheticRadiometry.apply( ...
    pair.MovingImage, renderer.BitDepth, string(r.kind), ...
    Gain=double(r.gain), Offset=double(r.offset), ...
    Gamma=double(r.gamma), BlurSigmaPixels=double(r.blurSigmaPixels), ...
    NoiseSigma=double(r.noiseSigma), Seed=double(r.seed));
c = prepareControl(renderer, pair, renderer.SearchRangeMetres, ...
    calibrator, false);
end

function c = prepareControl(renderer, pair, range, calibrator, knownCoarse)
levels = single(2 ^ renderer.BitDepth - 1);
reference = single(pair.ReferenceImage) ./ levels;
moving = single(pair.MovingImage) ./ levels;
solver = HierarchicalHeightSolver( ...
    renderer.ReferenceCamera, renderer.MovingCamera, reference, moving, ...
    ReferenceValid=pair.ReferenceValid, MovingValid=pair.MovingValid, ...
    PyramidFactors=[2, 1]);
overview = solver.runOverview(range, GeometrySampleGrid=[7, 7], ...
    TileSize=ceil(renderer.ImageSize ./ 2), LabelBlockSize=4, ...
    UseParallel=false);
if knownCoarse
    sz = overview.Pyramid.ReferenceLevelSize;
    overview.Sgm.HeightMetres = ...
        renderer.TrueHeightMetres .* ones(sz);
    overview.Sgm.Valid = overview.OverviewInput.ReferenceValid;
    overview.Sgm.LabelIndex = 2 .* ones(sz);
    overview.Raw.CostMargin = ones(sz);
    overview.Raw.LocalCurvaturePerMetreSquared = 0.01 .* ones(sz);
    overview.Raw.ObservabilityPixelsPerMetre = 0.1 .* ones(sz);
    overview.Warnings.RawBoundaryWinner = false(sz);
    overview.Warnings.SgmBoundaryWinner = false(sz);
    overview.Warnings.InvalidOutput = ...
        ~overview.OverviewInput.ReferenceValid;
end
tileSize = max(16, ceil(renderer.ImageSize ./ 2));
plan = solver.prepareNextLevel(overview, calibrator, ...
    TileSize=tileSize, GeometrySampleGrid=[3, 3]);
c = struct( ...
    "Identifier", renderer.Identifier, ...
    "SurfaceType", renderer.SurfaceType, ...
    "TextureType", pair.TextureType, ...
    "ImageSize", renderer.ImageSize, ...
    "TrueHeightMetres", renderer.TrueHeightMetres, ...
    "Solver", solver, "Plan", plan, ...
    "Truth", sceneTruth(renderer, pair));
end

function truth = sceneTruth(renderer, pair)
[y, x] = ndgrid(1:renderer.ImageSize(1), 1:renderer.ImageSize(2));
p = [x(:), y(:)];
if renderer.SurfaceType == "hillside-buildings"
    [~, z, vr, kind] = PinholeHillsideBuildingsOracle.intersect( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.SurfaceSlopeENU, renderer.TerrainCurvaturePerMetre, ...
        renderer.Buildings, CurvatureCenterENU=renderer.CurvatureCenterENU);
    [w, vg, inside, visible] = ...
        PinholeHillsideBuildingsOracle.correspondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.SurfaceSlopeENU, ...
        renderer.TerrainCurvaturePerMetre, renderer.Buildings, ...
        CurvatureCenterENU=renderer.CurvatureCenterENU);
    valid = vr & vg & inside & visible;
    occluded = vr & vg & inside & ~visible;
else
    [z, ~, ~, vr] = PinholePlaneOracle.surfaceHeight( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.SurfaceSlopeENU);
    [w, vg, inside] = PinholePlaneOracle.surfaceCorrespondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.SurfaceSlopeENU);
    valid = vr & vg & inside;
    kind = ones(size(vr), "uint8");
    occluded = false(size(vr));
end
referenceValid = vr & pair.ReferenceValid(:);
movingSupport = interp2(double(pair.MovingValid), w(:, 1), w(:, 2), ...
    "linear", 0) >= 1 - 64 .* eps;
valid = valid & referenceValid & movingSupport;
z(~referenceValid) = NaN;
w(~valid, :) = NaN;
facade = referenceValid & (kind == 3 | kind == 4);
occluded = referenceValid & occluded;
truth = struct( ...
    "HeightMetres", reshape(z, renderer.ImageSize), ...
    "CorrespondenceXY", reshape(w, [renderer.ImageSize, 2]), ...
    "ReferenceValid", reshape(referenceValid, renderer.ImageSize), ...
    "Valid", reshape(valid, renderer.ImageSize), ...
    "SurfaceKind", reshape(kind, renderer.ImageSize), ...
    "FacadeFraction", nnz(facade) ./ max(nnz(referenceValid), 1), ...
    "OcclusionFraction", nnz(occluded) ./ max(nnz(referenceValid), 1));
end

function m = truthMetrics(product, truth)
valid = truth.Valid & product.Valid ...
    & isfinite(product.CorrespondenceXY(:, :, 1)) ...
    & isfinite(product.CorrespondenceXY(:, :, 2));
dx = product.CorrespondenceXY(:, :, 1) ...
    - truth.CorrespondenceXY(:, :, 1);
dy = product.CorrespondenceXY(:, :, 2) ...
    - truth.CorrespondenceXY(:, :, 2);
epe = hypot(dx(valid), dy(valid));
m = struct( ...
    "Coverage", nnz(valid) ./ max(nnz(truth.Valid), 1), ...
    "EpeRmsePixels", rootMeanSquare(epe), ...
    "EpeP95Pixels", finitePercentile(epe, 95));
end

function m = emptyTruthMetrics
m = struct("Coverage", NaN, "EpeRmsePixels", NaN, ...
    "EpeP95Pixels", NaN);
end

function value = rootMeanSquare(x)
if isempty(x)
    value = NaN;
else
    value = sqrt(mean(x .^ 2));
end
end

function value = finitePercentile(x, q)
x = sort(x(isfinite(x)));
if isempty(x)
    value = NaN;
    return
end
position = 1 + (numel(x) - 1) .* q ./ 100;
lo = floor(position);
hi = ceil(position);
value = x(lo) + (position - lo) .* (x(hi) - x(lo));
end

function names = adaptiveTriggerNames
names = ["InheritedRawBoundary", "InheritedSgmBoundary", ...
    "InheritedInvalidOutput", "InheritedLowConfidence", ...
    "InheritedConfidenceInvalid", "HighTrajectoryCurvature", ...
    "UnderDenseLabels", "FineBoundaryWinner", "FineInvalidOutput", ...
    "CoarseFineDisagreement"];
end

function calibrator = frozenCalibrator(root)
path = fullfile(root, "config", "synthetic", ...
    "height_label_density_study_v4.json");
study = jsondecode(fileread(path));
calibrator = HeightConfidenceCalibrator.fromStruct( ...
    study.failureDetection.frozenConfidence);
end

function figureHandle = displayControls(summary)
figureHandle = figure(Name="Adaptive hierarchy controls");
tiledlayout(1, 2, TileSpacing="compact", Padding="compact");
nexttile;
bar(categorical(summary.Scenario), summary.WorkRatio);
ylabel("adaptive / full pixel-label work");
grid on;
nexttile;
values = [summary.FullComparisonEpeRmsePixels, ...
    summary.RawTruthEpeRmsePixels];
names = ["adaptive WTA vs full WTA", "adaptive WTA vs truth"];
if any(isfinite(summary.SgmTruthEpeRmsePixels))
    values(:, end + 1) = summary.SgmTruthEpeRmsePixels;
    names(end + 1) = "adaptive SGM vs truth";
end
bar(categorical(summary.Scenario), values);
ylabel("endpoint RMSE (pixels)");
legend(names, Location="best");
grid on;
end

function mustBeControlScenarios(names)
allowed = ["clean", "out-of-range", "under-dense", ...
    "low-texture", "facade-occlusion"];
mustBeMember(names, allowed);
if numel(unique(names)) ~= numel(names)
    error("runAdaptiveHierarchyControls:DuplicateScenario", ...
        "Scenarios must not contain duplicates.");
end
end
